-- Find the test user
SELECT id, phoneE164, firstName, lastName, paymentMethodSaved, stripeCustomerId FROM bldg_users ORDER BY id DESC LIMIT 5;

-- Clear chat messages
DELETE FROM chat_messages WHERE bldg_user_id IN (SELECT id FROM bldg_users);

-- Clear service requests
DELETE FROM service_requests WHERE bldg_user_id IN (SELECT id FROM bldg_users);

-- Reset payment flag and customer ID
UPDATE bldg_users SET paymentMethodSaved = 0, stripeCustomerId = NULL;

-- Clear onboarding flags
DELETE FROM onboarding_flags WHERE bldg_user_id IN (SELECT id FROM bldg_users);

-- Verify reset
SELECT id, phoneE164, firstName, lastName, paymentMethodSaved, stripeCustomerId FROM bldg_users;

